 1	import * as React from 'react';
 2	import classNames from 'classnames';
 3	import { Tabs, Tab } from '@patternfly/react-core';
 4	
 5	export type Tab = {
 6	  name: string;
 7	  component: React.FunctionComponent<{}> | React.ReactElement;
 8	};
 9	
10	type SimpleTabNavProps = {
11	  onClickTab?: (name: string) => void;
12	  selectedTab?: string;
13	  tabProps?: any;
14	  tabs: Tab[];
15	  additionalClassNames?: string;
16	  withinSidebar?: boolean;
17	  noInset?: boolean;
18	};
19	
20	export const SimpleTabNav: React.FC<SimpleTabNavProps> = ({
21	  onClickTab,
22	  selectedTab,
23	  tabProps = null,
24	  tabs,
25	  additionalClassNames,
26	  withinSidebar,
27	  noInset,
28	}) => {
29	  const [activeKey, setActiveKey] = React.useState<string>(
30	    selectedTab || tabs[0]?.name,
31	  );
32	
33	  const handleTabClick = (_e, tabIndex: string) => {
34	    setActiveKey(tabIndex);
35	    onClickTab && onClickTab(tabIndex);
36	  };
37	
38	  return (
39	    <div>
40	      <Tabs
41	        activeKey={activeKey}
42	        onSelect={handleTabClick}
43	        className={classNames(
44	          { 'pf-u-mb-md': withinSidebar },
45	          additionalClassNames,
46	        )}
47	        unmountOnExit
48	      >
49	        {tabs.map((tab) => {
50	          const content =
51	            !React.isValidElement(tab.component) &&
52	            !Array.isArray(tab.component)
53	              ? React.createElement(
54	                  tab.component as React.FunctionComponent,
55	                  tabProps,
56	                )
57	              : tab.component;
58	
59	          return (
60	            <Tab
61	              key={tab.name}
62	              eventKey={tab.name}
63	              title={tab.name}
64	              data-test={`horizontal-link-${tab.name}`}
65	            >
66	              {content}
67	            </Tab>
68	          );
69	        })}
70	      </Tabs>
71	    </div>
72	  );
73	};

